func:
let marca = msg.payload.marca;
let modelo = msg.payload.modelo;
let sintomas = msg.payload.sintomas;

if (!marca || marca.trim() === "" ||
    !modelo || modelo.trim() === "" ||
    !sintomas || sintomas.trim() === "") {
    return null;
}

return msg;

let marca = (msg.payload.marca || "").toLowerCase().trim();
let modelo = (msg.payload.modelo || "").toLowerCase().trim();
let s = (msg.payload.sintomas || "").toLowerCase().trim();

let resultados = [];

// SÍNTOMAS
if (s.includes("humo negro")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible mezcla rica o problema de inyección",
        prioridad: "media",
        recomendacion: "Revisar inyectores, filtro de aire y sistema de admisión"
    });
}

if (s.includes("humo blanco")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible entrada de refrigerante en la combustión",
        prioridad: "alta",
        recomendacion: "Comprobar junta de culata, nivel de refrigerante y estanqueidad del circuito"
    });
}

if (s.includes("humo azul")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible consumo de aceite por desgaste interno",
        prioridad: "media",
        recomendacion: "Revisar segmentos, retenes de válvula y nivel de aceite"
    });
}

if (s.includes("fuga de aceite")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible fuga en juntas o retenes",
        prioridad: "media",
        recomendacion: "Inspeccionar cárter, tapa de balancines, retenes y zonas de sellado"
    });
}

if (s.includes("perdida de potencia") || s.includes("pérdida de potencia")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible fallo en admisión, turbo o alimentación",
        prioridad: "alta",
        recomendacion: "Revisar turbo, caudalímetro, filtro de combustible y presión de admisión"
    });
}

if (s.includes("tirones")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible fallo de combustión o alimentación",
        prioridad: "media",
        recomendacion: "Comprobar bujías, bobinas, inyectores o suministro de combustible"
    });
}

if (s.includes("vibracion") || s.includes("vibración")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible desequilibrio mecánico o problema de frenos/suspensión",
        prioridad: "media",
        recomendacion: "Revisar ruedas, discos, soportes y elementos de suspensión"
    });
}

if (s.includes("silbido turbo")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible fuga o desgaste en el sistema de sobrealimentación",
        prioridad: "alta",
        recomendacion: "Inspeccionar manguitos, turbo e intercooler"
    });
}

if (s.includes("testigo motor") || s.includes("check engine")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Avería electrónica o de emisiones pendiente de lectura DTC",
        prioridad: "media",
        recomendacion: "Leer códigos OBD-II y relacionarlos con la base de conocimiento"
    });
}

if (s.includes("no arranca")) {
    resultados.push({
        tipo: "síntoma",
        codigo: null,
        diagnostico: "Posible fallo de batería, arranque o alimentación",
        prioridad: "alta",
        recomendacion: "Comprobar batería, motor de arranque, fusibles y suministro de combustible"
    });
}

// CÓDIGOS DTC
if (s.includes("p0300")) {
    resultados.push({
        tipo: "DTC",
        codigo: "P0300",
        diagnostico: "Fallos de encendido aleatorios o múltiples detectados",
        prioridad: "alta",
        recomendacion: "Revisar bujías, bobinas, inyectores, admisión y compresión"
    });
}

if (s.includes("p0171")) {
    resultados.push({
        tipo: "DTC",
        codigo: "P0171",
        diagnostico: "Mezcla demasiado pobre en banco 1",
        prioridad: "alta",
        recomendacion: "Comprobar fugas de admisión, caudalímetro, presión de combustible e inyectores"
    });
}

if (s.includes("p0401")) {
    resultados.push({
        tipo: "DTC",
        codigo: "P0401",
        diagnostico: "Flujo insuficiente en el sistema EGR",
        prioridad: "media",
        recomendacion: "Revisar válvula EGR, conductos y posible acumulación de carbonilla"
    });
}

if (s.includes("p0420")) {
    resultados.push({
        tipo: "DTC",
        codigo: "P0420",
        diagnostico: "Eficiencia del catalizador por debajo del umbral",
        prioridad: "media",
        recomendacion: "Comprobar catalizador, sonda lambda y posibles fallos previos de combustión"
    });
}

if (resultados.length === 0) {
    resultados.push({
        tipo: "desconocido",
        codigo: null,
        diagnostico: "Avería no identificada con la regla actual",
        prioridad: "revisar",
        recomendacion: "Añadir más síntomas o consultar códigos DTC para afinar el diagnóstico"
    });
}

msg.payload = {
    marca: marca,
    modelo: modelo,
    entrada: msg.payload.sintomas,
    resultados: resultados
};

return msg;

let texto = "";

msg.payload.resultados.forEach((r, i) => {
    texto += "Avería " + (i + 1) + ": " + r.diagnostico + "\n";
    texto += "Gravedad: " + r.prioridad + "\n";
    texto += "Recomendación: " + r.recomendacion + "\n";

    if (r.codigo) {
        texto += "Código DTC: " + r.codigo + "\n";
    }

    texto += "\n";
});

msg.payload = texto;
return msg;
